const body = $input.first().json.body || {};
if (!body.project_id) { const e = { valid:false, error:'project_id obligatorio' }; return [{ json: e }]; }
const valid = ['aftercare_submit','project_view','full_access','client_ask'];
const purpose = body.purpose || 'aftercare_submit';
if (!valid.includes(purpose)) {
  const e = { valid:false, error:'purpose debe ser '+valid.join('|') };
  return [{ json: e }];
}
const expiresDays = Number(body.expires_days) || 90;
const out = {
  valid: true,
  project_id: body.project_id,
  purpose: purpose,
  expires_days: expiresDays,
  notes: (body.notes || '').toString().slice(0, 500)
};
return [{ json: out }];

const r = $input.first().json;
const N8N = 'https://n8n-n8n.zzeluw.easypanel.host';
const urls = {};
if (r.purpose === 'aftercare_submit' || r.purpose === 'full_access') {
  urls.aftercare_form = N8N + '/webhook/aftercare-public-form?token=' + encodeURIComponent(r.token);
}
if (r.purpose === 'project_view' || r.purpose === 'full_access') {
  urls.project_summary = N8N + '/webhook/project-summary?token=' + encodeURIComponent(r.token);
}
if (r.purpose === 'client_ask' || r.purpose === 'full_access') {
  urls.client_ask_endpoint = N8N + '/webhook/client-ask';
  urls.client_ask_token = r.token;
  urls.client_ask_form = N8N + '/webhook/client-ask-form?token=' + encodeURIComponent(r.token);
}
return [{ json: { token_id: r.id, token: r.token, project_id: r.project_id, client_id: r.client_id, purpose: r.purpose, expires_at: r.expires_at, urls: urls } }];
